    for dr in (-1, 0, 1):
        for dc in (-1, 0, 1):
            if dr == 0 and dc == 0:
                continue
            dirs.append((dr, dc))

    # Find the unique sequence
    for r in range(H):
        for c in range(W):
            if S[r][c] != word[0]:
                continue
            for dr, dc in dirs:
                rr = r + dr * (k - 1)
                cc = c + dc * (k - 1)
                if not (0 <= rr < H and 0 <= cc < W):
                    continue
                ok = True
                coords = []
                for t in range(k):
                    nr = r + dr * t
                    nc = c + dc * t
                    if S[nr][nc] != word[t]:
                        ok = False
                        break
                    coords.append((nr + 1, nc + 1))  # 1-indexed
                if ok:
                    for R, C in coords:
                        print(R, C)
